const name = 'Alice';

function Greeting() {
  return <h1>Hello, {name}!</h1>;
  //               ^^^^^^ expression between tags
}

const avatarUrl = 'https://example.com/alice.jpg';

function Avatar() {
  return <img src={avatarUrl} alt={name} />;
  //          ^^^^^^^^^^^^ ^^^^^^^^^^ expression in attribute
}

const user = { name: 'Alice', score: 84, joinedAt: new Date('2023-01-15') };
const items = ['Apple', 'Banana', 'Cherry'];

function Examples() {
  return (
    <ul>
      {/* Variable */}
      <li>{user.name}</li>

      {/* Arithmetic */}
      <li>{user.score * 1.1}</li>

      {/* String method */}
      <li>{user.name.toLowerCase()}</li>

      {/* Template literal */}
      <li>{`Joined: ${user.joinedAt.getFullYear()}`}</li>

      {/* Ternary */}
      <li>{user.score >= 90 ? 'A' : user.score >= 80 ? 'B' : 'C'}</li>

      {/* Array.map — returns array of JSX */}
      {items.map(item => <li key={item}>{item}</li>)}

      {/* Function call returning JSX */}
      <li>{formatScore(user.score)}</li>
    </ul>
  );
}

function formatScore(n) {
  return <strong>{n}/100</strong>;
}

// ✗ SyntaxError — if is a statement
<p>{if (user.score > 90) { 'A' }}</p>

// ✗ SyntaxError — for is a statement
<ul>{for (const item of items) { <li>{item}</li> }}</ul>

// ✗ SyntaxError — let declaration is a statement
<p>{let x = 5; x * 2}</p>

function Grade({ score }) {
  // Statements live here — in the function body, not JSX
  let grade;
  if (score >= 90) grade = 'A';
  else if (score >= 80) grade = 'B';
  else grade = 'C';

  // Only the result goes in JSX
  return <p>Grade: {grade}</p>;
}

function UserBio({ user }) {
  return (
    <div>
      {/* ?? provides a fallback when value is null or undefined */}
      <p>{user.bio ?? 'No bio provided'}</p>

      {/* ?. safely accesses nested property — avoids TypeError */}
      <p>{user.address?.city ?? 'City unknown'}</p>
    </div>
  );
}

const products = [
  { id: 1, name: 'Keyboard', price: 79 },
  { id: 2, name: 'Mouse',    price: 49 },
  { id: 3, name: 'Monitor',  price: 299 },
];

function ProductList() {
  return (
    <ul>
      {products.map(p => (
        <li key={p.id}>
          {p.name} — ${p.price}
        </li>
      ))}
    </ul>
  );
}

function AffordableList({ products, maxPrice }) {
  return (
    <ul>
      {products
        .filter(p => p.price <= maxPrice)
        .map(p => <li key={p.id}>{p.name}</li>)
      }
    </ul>
  );
}

function Button({ variant, disabled, onClick, label }) {
  // Computed class name
  const cls = `btn btn-${variant} ${disabled ? 'btn-disabled' : ''}`;

  return (
    <button
      className={cls}
      disabled={disabled}
      onClick={onClick}
      style={{
        opacity: disabled ? 0.5 : 1,
        cursor: disabled ? 'not-allowed' : 'pointer',
      }}
      aria-label={label}
    >
      {label}
    </button>
  );
}

function Counter() {
  const [count, setCount] = useState(0);
  return (
    <div>
      <p>{count}</p>
      {/* Arrow function is an expression */}
      <button onClick={() => setCount(count + 1)}>+</button>
      {/* Function reference — also an expression */}
      <button onClick={() => setCount(0)}>Reset</button>
    </div>
  );
}

function Summary({ count, total }) {
  return (
    <p>
      Showing {count} of {total} result{total !== 1 ? 's' : ''}
    </p>
  );
  // Renders e.g.: Showing 5 of 100 results
  //               Showing 0 of 1 result
}

// Outer {} = expression context (JSX syntax)
// Inner {} = JavaScript object literal
<div style={{ backgroundColor: '#f0f', padding: 16 }}>

// Exactly the same as:
const divStyle = { backgroundColor: '#f0f', padding: 16 };
<div style={divStyle}>

function PriceTag({ price, currency }) {
  return (
    <span>
      {/* IIFE — valid but verbose; better to extract */}
      {(() => {
        const formatted = price.toFixed(2);
        const symbol = currency === 'EUR' ? '€' : '$';
        return `${symbol}${formatted}`;
      })()}
    </span>
  );
}

// Cleaner: move the logic to a helper
function formatPrice(price, currency) {
  const symbol = currency === 'EUR' ? '€' : '$';
  return `${symbol}${price.toFixed(2)}`;
}

function PriceTag({ price, currency }) {
  return <span>{formatPrice(price, currency)}</span>;
}

const metrics = [
  { id: 'revenue',  label: 'Revenue',  value: 12840, unit: '$', trend: +8.2 },
  { id: 'orders',   label: 'Orders',   value: 342,   unit: '',  trend: -3.1 },
  { id: 'visitors', label: 'Visitors', value: 9410,  unit: '',  trend: +12.5 },
];

function StatCard({ label, value, unit, trend }) {
  const positive = trend >= 0;
  return (
    <div className="stat-card">
      <h3>{label}</h3>
      <p className="value">{unit}{value.toLocaleString()}</p>
      <span className={positive ? 'trend-up' : 'trend-down'}>
        {positive ? '▲' : '▼'} {Math.abs(trend)}%
      </span>
    </div>
  );
}

function Dashboard() {
  return (
    <section>
      <h2>Today's Overview</h2>
      <div className="stats-grid">
        {metrics.map(m => (
          <StatCard
            key={m.id}
            label={m.label}
            value={m.value}
            unit={m.unit}
            trend={m.trend}
          />
        ))}
      </div>
    </section>
  );
}

// ✗ Objects are not valid React children
const user = { name: 'Alice', age: 30 };
return <p>{user}</p>; // TypeError: Objects are not valid as a React child

// ✔ Access specific properties
return <p>{user.name}, age {user.age}</p>;

const url = '/images/cat.jpg';

// ✗ Renders the literal string "{url}"
<img src="{url}" />

// ✔ Curly braces, no quotes
<img src={url} />

// ✗ Warning: Each child in a list should have a unique "key" prop
{items.map(item => <li>{item.name}</li>)}

// ✔ Add key
{items.map(item => <li key={item.id}>{item.name}</li>)}

// Hard to read — nested ternaries inside JSX
function OrderStatus({ status, estimatedDelivery }) {
  return (
    <p>
      {status === 'delivered' ? 'Delivered' :
        status === 'shipped' ? `Ships by ${estimatedDelivery}` :
        status === 'processing' ? 'Processing your order' :
        'Unknown status'}
    </p>
  );
}

// Clearer — logic extracted to a function
function describeStatus(status, estimatedDelivery) {
  switch (status) {
    case 'delivered':  return 'Delivered';
    case 'shipped':    return `Ships by ${estimatedDelivery}`;
    case 'processing': return 'Processing your order';
    default:           return 'Unknown status';
  }
}

function OrderStatus({ status, estimatedDelivery }) {
  return <p>{describeStatus(status, estimatedDelivery)}</p>;
}

function UserProfile({ user, currentUserId }) {
  // All derived values computed here
  const isOwner = user.id === currentUserId;
  const joinYear = new Date(user.joinedAt).getFullYear();
  const followerLabel = user.followers === 1 ? '1 follower' : `${user.followers} followers`;
  const avatarSrc = user.avatarUrl ?? '/default-avatar.png';

  // JSX is clean — just references to pre-computed values
  return (
    <div className="profile">
      <img src={avatarSrc} alt={user.name} />
      <h1>{user.name}</h1>
      <p>Member since {joinYear} · {followerLabel}</p>
      {isOwner && <button>Edit profile</button>}
    </div>
  );
}

function Article({ sections }) {
  // Render helper — just a function, not a component
  function renderSection(section) {
    if (section.type === 'text') {
      return <p key={section.id}>{section.body}</p>;
    }
    if (section.type === 'image') {
      return <img key={section.id} src={section.url} alt={section.caption} />;
    }
    if (section.type === 'quote') {
      return <blockquote key={section.id}>{section.body}</blockquote>;
    }
    return null;
  }

  return (
    <article>
      {sections.map(renderSection)}
    </article>
  );
}
